// ========================================================================
// ERWEITERTE VERGLEICHSLOGIK MIT DEPUTATS-TYP-TRACKING UND TERM-ZEITRAUM
// ========================================================================
// Datum: 04.02.2026
// NEU: Term-Zeitraum (TERM_ID, DateFrom, DateTo) für E-Mail-Anzeige
// Features:
// - Erkennung welches Deputat sich geändert hat (GES/GYM/BK)
// - OwnSchool und PNumber integriert
// - Detaillierte Change-Historie für jede Deputats-Art
// - NEU: Gültigkeitszeitraum der Periode
// ========================================================================

// Mit APPEND Mode kommen ALLE Items in einem Datenstrom
// Wir trennen sie anhand der Feldnamen (UPPERCASE = Untis, lowercase = Snapshot)

const allItems = $input.all();

// Items nach Quelle trennen
const untisItems = [];
const snapshotItems = [];

allItems.forEach(item => {
  // Untis-Daten haben UPPERCASE Feldnamen
  if (item.json.TEACHER_ID !== undefined) {
    untisItems.push(item.json);
  } 
  // Snapshot-Daten haben lowercase Feldnamen
  else if (item.json.teacher_id !== undefined) {
    snapshotItems.push(item.json);
  }
});

// ========================================================================
// NEU: TERM-ZEITRAUM EXTRAHIEREN (aus erstem Untis-Item)
// ========================================================================
let termInfo = {
  termId: null,
  termName: null,
  dateFrom: null,
  dateTo: null,
  termZeitraum: null,
  schuljahrText: null
};

if (untisItems.length > 0) {
  const firstItem = untisItems[0];
  termInfo = {
    termId: firstItem.TERM_ID,
    termName: firstItem.Term_Name || null,
    dateFrom: firstItem.DateFrom_Formatted || null,
    dateTo: firstItem.DateTo_Formatted || null,
    termZeitraum: firstItem.Term_Zeitraum || null,
    schuljahrText: firstItem.Schuljahr_Text
  };
}

// Map für schnellen Zugriff auf Snapshot-Daten
const snapshotMap = new Map();
snapshotItems.forEach(item => {
  const key = `${item.teacher_id}_${item.schoolyear_id}_${item.term_id}`;
  snapshotMap.set(key, item);
});

// ========================================================================
// HELPER FUNKTION: Deputats-Änderungen identifizieren
// ========================================================================
function identifiziereDeputatsAenderungen(gesAlt, gesNeu, gymAlt, gymNeu, bkAlt, bkNeu) {
  const aenderungen = [];

  const gesChange = parseFloat(gesNeu) - parseFloat(gesAlt);
  const gymChange = parseFloat(gymNeu) - parseFloat(gymAlt);
  const bkChange = parseFloat(bkNeu) - parseFloat(bkAlt);

  if (Math.abs(gesChange) > 0.001) {
    aenderungen.push({
      typ: 'GES',
      label: 'Gesamtschule',
      alt: parseFloat(gesAlt),
      neu: parseFloat(gesNeu),
      diff: gesChange,
      farbe: '#6BAA24'  // Grün (CREDO CD)
    });
  }

  if (Math.abs(gymChange) > 0.001) {
    aenderungen.push({
      typ: 'GYM',
      label: 'Gymnasium',
      alt: parseFloat(gymAlt),
      neu: parseFloat(gymNeu),
      diff: gymChange,
      farbe: '#FBC800'  // Gelb (CREDO CD)
    });
  }

  if (Math.abs(bkChange) > 0.001) {
    aenderungen.push({
      typ: 'BK',
      label: 'Berufskolleg',
      alt: parseFloat(bkAlt),
      neu: parseFloat(bkNeu),
      diff: bkChange,
      farbe: '#009ADE'  // Blau (CREDO CD)
    });
  }

  return aenderungen;
}

// ========================================================================
// HAUPTVERGLEICH
// ========================================================================
const aenderungen = [];
const alleDaten = [];

untisItems.forEach(data => {
  const key = `${data.TEACHER_ID}_${data.SCHOOLYEAR_ID}_${data.TERM_ID}`;
  const snapshot = snapshotMap.get(key);

  // ========================================================================
  // Für Snapshot speichern (mit neuen Feldern)
  // ========================================================================
  alleDaten.push({
    teacher_id: data.TEACHER_ID,
    schoolyear_id: data.SCHOOLYEAR_ID,
    term_id: data.TERM_ID,
    name: data.Name,
    personalnummer: data.Personalnummer || null,
    stammschule: data.Stammschule || null,
    vollname: data.Vollname,
    deputat: data.Deputat,
    deputat_ges: data.Deputat_GES,
    deputat_gym: data.Deputat_GYM,
    deputat_bk: data.Deputat_BK,
    schuljahr_text: data.Schuljahr_Text
  });

  // ========================================================================
  // VERGLEICH DURCHFÜHREN
  // ========================================================================
  if (snapshot) {
    const deputatAlt = parseFloat(snapshot.deputat) || 0;
    const deputatNeu = parseFloat(data.Deputat) || 0;
    const gesAlt = parseFloat(snapshot.deputat_ges) || 0;
    const gesNeu = parseFloat(data.Deputat_GES) || 0;
    const gymAlt = parseFloat(snapshot.deputat_gym) || 0;
    const gymNeu = parseFloat(data.Deputat_GYM) || 0;
    const bkAlt = parseFloat(snapshot.deputat_bk) || 0;
    const bkNeu = parseFloat(data.Deputat_BK) || 0;

    // Prüfe ob sich IRGENDETWAS geändert hat
    if (deputatAlt !== deputatNeu || gesAlt !== gesNeu || gymAlt !== gymNeu || bkAlt !== bkNeu) {

      // Identifiziere welche Deputate sich geändert haben
      const deputatsAenderungen = identifiziereDeputatsAenderungen(
        gesAlt, gesNeu, gymAlt, gymNeu, bkAlt, bkNeu
      );

      aenderungen.push({
        vollname: data.Vollname,
        name: data.Name,
        personalnummer: data.Personalnummer || 'N/A',
        stammschule: data.Stammschule || 'N/A',
        schuljahr: data.Schuljahr_Text,
        deputat_alt: deputatAlt,
        deputat_neu: deputatNeu,
        deputat_diff: (deputatNeu - deputatAlt).toFixed(2),
        ges_alt: gesAlt,
        ges_neu: gesNeu,
        gym_alt: gymAlt,
        gym_neu: gymNeu,
        bk_alt: bkAlt,
        bk_neu: bkNeu,
        deputatsAenderungen: deputatsAenderungen,
        typ: 'GEÄNDERT'
      });
    }
  } else {
    // NEUER Lehrer
    const deputatsAenderungen = identifiziereDeputatsAenderungen(
      0, parseFloat(data.Deputat_GES) || 0,
      0, parseFloat(data.Deputat_GYM) || 0,
      0, parseFloat(data.Deputat_BK) || 0
    );

    aenderungen.push({
      vollname: data.Vollname,
      name: data.Name,
      personalnummer: data.Personalnummer || 'N/A',
      stammschule: data.Stammschule || 'N/A',
      schuljahr: data.Schuljahr_Text,
      deputat_alt: 0,
      deputat_neu: parseFloat(data.Deputat) || 0,
      deputat_diff: parseFloat(data.Deputat) || 0,
      ges_alt: 0,
      ges_neu: parseFloat(data.Deputat_GES) || 0,
      gym_alt: 0,
      gym_neu: parseFloat(data.Deputat_GYM) || 0,
      bk_alt: 0,
      bk_neu: parseFloat(data.Deputat_BK) || 0,
      deputatsAenderungen: deputatsAenderungen,
      typ: 'NEU'
    });
  }
});

// ========================================================================
// ÜBERLAST / UNTERLAST STATISTIK
// ========================================================================
let ueberlastCount = 0;
let unterlastCount = 0;

aenderungen.forEach(a => {
  const diff = parseFloat(a.deputat_diff);
  if (diff > 0.5) ueberlastCount++;
  if (diff < -0.5) unterlastCount++;
});

// ========================================================================
// RÜCKGABE (MIT TERM-INFO)
// ========================================================================
return {
  hatAenderungen: aenderungen.length > 0,
  anzahlAenderungen: aenderungen.length,
  aenderungen: aenderungen,
  alleDaten: alleDaten,
  datum: new Date().toISOString().split('T')[0],
  // NEU: Term-Zeitraum Informationen
  termInfo: termInfo,
  // Statistik
  statistik: {
    ueberlast: ueberlastCount,
    unterlast: unterlastCount,
    gesamt: aenderungen.length
  }
};

// ========================================================================
// OUTLOOK-KOMPATIBLE E-MAIL-VORLAGE MIT TERM-ZEITRAUM
// ========================================================================
// Datum: 04.02.2026
// FIXES:
// - VML-Fallback für Outlook (linear-gradient funktioniert nicht!)
// - Keine rgba() oder opacity (Outlook-inkompatibel)
// - Deutsches Datumsformat
// - Begrüßung: "Hallo liebes Team der Personalabteilung,"
// - Meta charset UTF-8 hinzugefügt
// - HTML-Entities für Umlaute
// ========================================================================

// Daten aus dem vorherigen Node holen
const inputData = $('Vergleich durchführen').first().json;
const aenderungen = inputData.aenderungen || [];
const termInfo = inputData.termInfo || {};
const statistik = inputData.statistik || { ueberlast: 0, unterlast: 0, gesamt: 0 };

// ========================================================================
// DEUTSCHES DATUMSFORMAT
// ========================================================================
const heute = new Date();
const datumFormatiert = heute.toLocaleDateString('de-DE', {
  day: '2-digit',
  month: '2-digit',
  year: 'numeric'
});

// ========================================================================
// TERM-ZEITRAUM INFORMATION
// ========================================================================
const termId = termInfo.termId || 'N/A';
const termZeitraum = termInfo.termZeitraum || 'Zeitraum nicht verfügbar';
const dateFrom = termInfo.dateFrom || 'N/A';
const dateTo = termInfo.dateTo || 'N/A';
const schuljahrText = termInfo.schuljahrText || 'N/A';

// ========================================================================
// FIX 27.02.2026: GRUPPIERUNG NACH STAMMSCHULE-STRING (GYM/GES/BK)
// OwnSchool liefert Strings ('GYM','GES','BK'), nicht numerische IDs
// ========================================================================
const SCHULFORM_CONFIG = {
  'GYM': { label: 'Gymnasium', farbe: '#FBC900', reihenfolge: 1 },
  'GES': { label: 'Gesamtschule', farbe: '#6BAA24', reihenfolge: 2 },
  'BK':  { label: 'Berufskolleg', farbe: '#5C82A5', reihenfolge: 3 }
};

// Sortierung: nach Schulform-Reihenfolge, dann alphabetisch
const aenderungenSortiert = [...aenderungen].sort((a, b) => {
  const aOrder = (SCHULFORM_CONFIG[String(a.stammschule).toUpperCase()] || {}).reihenfolge || 99;
  const bOrder = (SCHULFORM_CONFIG[String(b.stammschule).toUpperCase()] || {}).reihenfolge || 99;

  if (aOrder !== bOrder) return aOrder - bOrder;
  return a.vollname.localeCompare(b.vollname);
});

// Dynamische Gruppierung nach allen vorhandenen Stammschulen
const gruppiert = {};
aenderungenSortiert.forEach(a => {
  const key = String(a.stammschule || 'UNBEKANNT').toUpperCase();
  if (!gruppiert[key]) gruppiert[key] = [];
  gruppiert[key].push(a);
});

// ========================================================================
// CREDO CORPORATE DESIGN KONFIGURATION
// ========================================================================
const CD = {
  colors: {
    darkGrey: '#575756',
    lightGrey: '#F2F2F2',
    white: '#FFFFFF',
    text: '#333333',
    ges: '#6BAA24',
    gym: '#FBC900',
    bk: '#5C82A5',
    red: '#E2001A',
    success: '#6BAA24',
    error: '#E2001A',
    neutral: '#575756'
  }
};

// ========================================================================
// HELPER FUNKTIONEN
// ========================================================================
function generiereDeputatZelle(wert, farbe) {
  if (!wert || wert === 0 || wert === '0') {
    return '<span style="color: #cccccc; font-size: 12px;">&mdash;</span>';
  }
  const wertNum = parseFloat(wert);
  return `
    <table border="0" cellspacing="0" cellpadding="0" style="display: inline-block;">
      <tr>
        <td style="background-color: ${farbe}; color: #FFFFFF; padding: 5px 10px; border-radius: 4px; font-size: 13px; font-weight: 700; text-align: center; min-width: 45px;">
          ${wertNum.toFixed(2)}
        </td>
      </tr>
    </table>
  `;
}

function generiereDeputatsDetails(row) {
  const details = [];

  if (row.ges_neu > 0 || row.ges_alt > 0) {
    const gesDiff = (row.ges_neu - row.ges_alt).toFixed(2);
    const gesPrefix = parseFloat(gesDiff) > 0 ? '+' : '';
    const gesColor = parseFloat(gesDiff) >= 0 ? CD.colors.success : CD.colors.error;
    details.push(`
      <div style="margin: 2px 0; font-size: 11px; line-height: 1.4;">
        <span style="color: ${CD.colors.ges}; font-weight: 700;">&#9632;</span>
        <strong>GES:</strong> ${row.ges_alt} &rarr; ${row.ges_neu} 
        <span style="color: ${gesColor};">(${gesPrefix}${gesDiff})</span>
      </div>
    `);
  }

  if (row.gym_neu > 0 || row.gym_alt > 0) {
    const gymDiff = (row.gym_neu - row.gym_alt).toFixed(2);
    const gymPrefix = parseFloat(gymDiff) > 0 ? '+' : '';
    const gymColor = parseFloat(gymDiff) >= 0 ? CD.colors.success : CD.colors.error;
    details.push(`
      <div style="margin: 2px 0; font-size: 11px; line-height: 1.4;">
        <span style="color: ${CD.colors.gym}; font-weight: 700;">&#9632;</span>
        <strong>GYM:</strong> ${row.gym_alt} &rarr; ${row.gym_neu} 
        <span style="color: ${gymColor};">(${gymPrefix}${gymDiff})</span>
      </div>
    `);
  }

  if (row.bk_neu > 0 || row.bk_alt > 0) {
    const bkDiff = (row.bk_neu - row.bk_alt).toFixed(2);
    const bkPrefix = parseFloat(bkDiff) > 0 ? '+' : '';
    const bkColor = parseFloat(bkDiff) >= 0 ? CD.colors.success : CD.colors.error;
    details.push(`
      <div style="margin: 2px 0; font-size: 11px; line-height: 1.4;">
        <span style="color: ${CD.colors.bk}; font-weight: 700;">&#9632;</span>
        <strong>BK:</strong> ${row.bk_alt} &rarr; ${row.bk_neu} 
        <span style="color: ${bkColor};">(${bkPrefix}${bkDiff})</span>
      </div>
    `);
  }

  return details.length > 0 ? details.join('') : '<span style="color: #999999; font-size: 11px;">Keine Details</span>';
}

function generiereGruppenHeader(titel, farbe, anzahl) {
  return `
    <tr>
      <td colspan="10" style="padding: 20px 15px 10px 15px; background-color: ${CD.colors.lightGrey}; border-top: 3px solid ${farbe};">
        <table border="0" cellspacing="0" cellpadding="0">
          <tr>
            <td style="font-size: 14px; font-weight: 700; color: ${farbe}; text-transform: uppercase; letter-spacing: 1.5px; font-family: Calibri, Arial, sans-serif;">
              ${titel}
            </td>
            <td style="padding-left: 10px;">
              <table border="0" cellspacing="0" cellpadding="0">
                <tr>
                  <td style="background-color: ${farbe}; color: #FFFFFF; padding: 3px 8px; border-radius: 10px; font-size: 11px; font-weight: 700; font-family: Calibri, Arial, sans-serif;">
                    ${anzahl}
                  </td>
                </tr>
              </table>
            </td>
          </tr>
        </table>
      </td>
    </tr>
  `;
}

function generiereZeile(row, index) {
  const diff = parseFloat(row.deputat_diff);
  let diffColor = CD.colors.neutral;
  let diffPrefix = '';

  if (diff > 0) {
    diffColor = CD.colors.success;
    diffPrefix = '+';
  } else if (diff < 0) {
    diffColor = CD.colors.error;
  }

  const bgStyle = index % 2 === 0 ? CD.colors.white : '#FAFAFA';
  const badgeColor = row.typ === 'NEU' ? CD.colors.success : CD.colors.gym;
  const badgeTextColor = row.typ === 'NEU' ? '#FFFFFF' : '#333333';

  const stammschuleKey = String(row.stammschule || 'N/A').toUpperCase();
  const stammschuleLabel = (SCHULFORM_CONFIG[stammschuleKey] || {}).label || stammschuleKey;

  return `
    <tr style="background-color: ${bgStyle};">
      <td style="padding: 12px 15px; border-bottom: 1px solid #eeeeee; font-size: 14px; color: ${CD.colors.text}; font-weight: 600; vertical-align: top; font-family: Calibri, Arial, sans-serif;">
        ${row.vollname}
        <div style="font-size: 11px; color: #999999; font-weight: 400; margin-top: 3px;">
          PN: ${row.personalnummer} | Stammschule: ${stammschuleLabel}
        </div>
      </td>
      <td style="padding: 12px 15px; border-bottom: 1px solid #eeeeee; font-size: 14px; color: #666666; text-align: center; vertical-align: top; font-family: Calibri, Arial, sans-serif;">${row.name}</td>
      <td style="padding: 12px 15px; border-bottom: 1px solid #eeeeee; font-size: 14px; color: #666666; text-align: center; vertical-align: top; font-family: Calibri, Arial, sans-serif;">${row.deputat_alt}</td>
      <td style="padding: 12px 15px; border-bottom: 1px solid #eeeeee; font-size: 14px; color: ${CD.colors.text}; font-weight: 700; text-align: center; vertical-align: top; font-family: Calibri, Arial, sans-serif;">${row.deputat_neu}</td>
      <td style="padding: 12px 15px; border-bottom: 1px solid #eeeeee; font-size: 14px; color: ${diffColor}; font-weight: 700; text-align: center; vertical-align: top; font-family: Calibri, Arial, sans-serif;">${diffPrefix}${diff}</td>
      <td style="padding: 8px 10px; border-bottom: 1px solid #eeeeee; text-align: center; vertical-align: middle;">${generiereDeputatZelle(row.ges_neu, CD.colors.ges)}</td>
      <td style="padding: 8px 10px; border-bottom: 1px solid #eeeeee; text-align: center; vertical-align: middle;">${generiereDeputatZelle(row.gym_neu, CD.colors.gym)}</td>
      <td style="padding: 8px 10px; border-bottom: 1px solid #eeeeee; text-align: center; vertical-align: middle;">${generiereDeputatZelle(row.bk_neu, CD.colors.bk)}</td>
      <td style="padding: 12px 15px; border-bottom: 1px solid #eeeeee; vertical-align: top; font-family: Calibri, Arial, sans-serif;">${generiereDeputatsDetails(row)}</td>
      <td style="padding: 12px 15px; border-bottom: 1px solid #eeeeee; text-align: right; vertical-align: top;">
        <table border="0" cellspacing="0" cellpadding="0" style="display: inline-block;">
          <tr>
            <td style="background-color: ${badgeColor}; color: ${badgeTextColor}; padding: 4px 10px; border-radius: 12px; font-size: 11px; font-weight: 700; text-transform: uppercase; letter-spacing: 0.5px; font-family: Calibri, Arial, sans-serif;">
              ${row.typ}
            </td>
          </tr>
        </table>
      </td>
    </tr>
  `;
}

// ========================================================================
// TABELLEN-ZEILEN GENERIEREN
// ========================================================================
let tableRows = '';

// Dynamisch alle Stammschul-Gruppen rendern (sortiert nach Reihenfolge)
const gruppenKeys = Object.keys(gruppiert).sort((a, b) => {
  const aOrder = (SCHULFORM_CONFIG[a] || {}).reihenfolge || 99;
  const bOrder = (SCHULFORM_CONFIG[b] || {}).reihenfolge || 99;
  return aOrder - bOrder;
});

gruppenKeys.forEach(key => {
  const config = SCHULFORM_CONFIG[key] || { label: key, farbe: CD.colors.darkGrey };
  const gruppe = gruppiert[key];
  tableRows += generiereGruppenHeader(config.label, config.farbe, gruppe.length);
  gruppe.forEach((row, index) => {
    tableRows += generiereZeile(row, index);
  });
});

// ========================================================================
// HTML E-MAIL TEMPLATE - OUTLOOK KOMPATIBEL
// ========================================================================
const html = `
<!DOCTYPE html>
<html xmlns:v="urn:schemas-microsoft-com:vml" xmlns:o="urn:schemas-microsoft-com:office:office">
<head>
<meta charset="utf-8">
<meta http-equiv="Content-Type" content="text/html; charset=utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<!--[if mso]>
<xml>
  <o:OfficeDocumentSettings>
    <o:AllowPNG/>
    <o:PixelsPerInch>96</o:PixelsPerInch>
  </o:OfficeDocumentSettings>
</xml>
<style type="text/css">
body, table, td, p, a, span { font-family: Calibri, Arial, sans-serif !important; }
</style>
<![endif]-->
<style>
  body { margin: 0; padding: 0; background-color: #F2F2F2; font-family: Calibri, 'Segoe UI', Helvetica, Arial, sans-serif; -webkit-font-smoothing: antialiased; }
  table { border-collapse: collapse; mso-table-lspace: 0pt; mso-table-rspace: 0pt; }
  td { border-collapse: collapse; }
</style>
</head>
<body style="margin: 0; padding: 0; background-color: #F2F2F2;">
  <table width="100%" border="0" cellspacing="0" cellpadding="0" style="background-color: #F2F2F2;">
    <tr>
      <td align="center" style="padding: 20px 0;">
        <table width="900" border="0" cellspacing="0" cellpadding="0" style="background-color: #FFFFFF; border-radius: 8px;">

    <!-- HEADER -->
    <tr>
      <td style="padding: 40px 40px 30px 40px; background-color: #575756;">
        <p style="color: #FFFFFF; font-size: 12px; text-transform: uppercase; letter-spacing: 2px; margin: 0 0 10px 0; font-family: Calibri, Arial, sans-serif;">
          CREDO Verwaltung &middot; Deputatsverwaltung
        </p>
        <p style="color: #FFFFFF; font-size: 24px; margin: 0; font-weight: 700; letter-spacing: 0.5px; font-family: Calibri, Arial, sans-serif;">
          Deputat-&Auml;nderungsmonitor
        </p>
        <p style="color: #FFFFFF; font-size: 14px; margin: 5px 0 0 0; font-family: Calibri, Arial, sans-serif;">
          Automatische Auswertung vom ${datumFormatiert}
        </p>
      </td>
    </tr>

    <!-- TERM-ZEITRAUM BOX - OUTLOOK KOMPATIBEL (SOLID COLOR!) -->
    <tr>
      <td style="padding: 0;">
        <!--[if mso]>
        <v:rect xmlns:v="urn:schemas-microsoft-com:vml" fill="true" stroke="false" style="width:900px;height:90px;">
          <v:fill type="gradient" color="#FBC900" color2="#FFA500" angle="135"/>
          <v:textbox inset="0,0,0,0">
        <![endif]-->
        <table width="100%" border="0" cellspacing="0" cellpadding="0" style="background-color: #FBC900;">
          <tr>
            <td style="padding: 25px 40px;">
              <table width="100%" border="0" cellspacing="0" cellpadding="0">
                <tr>
                  <td width="60%" style="vertical-align: middle;">
                    <p style="color: #333333; font-size: 11px; text-transform: uppercase; letter-spacing: 2px; margin: 0 0 8px 0; font-family: Calibri, Arial, sans-serif;">
                      &#128197; G&uuml;ltigkeitszeitraum dieser &Auml;nderungen
                    </p>
                    <p style="color: #333333; font-size: 22px; font-weight: 700; margin: 0; letter-spacing: 0.5px; font-family: Calibri, Arial, sans-serif;">
                      ${termZeitraum}
                    </p>
                  </td>
                  <td width="40%" style="text-align: right; vertical-align: middle;">
                    <table border="0" cellspacing="0" cellpadding="0" align="right">
                      <tr>
                        <td style="background-color: #E5B400; padding: 10px 20px; border-radius: 8px;">
                          <p style="color: #333333; font-size: 11px; text-transform: uppercase; letter-spacing: 1px; margin: 0 0 5px 0; font-family: Calibri, Arial, sans-serif;">
                            Schuljahr
                          </p>
                          <p style="color: #333333; font-size: 18px; font-weight: 700; margin: 0; font-family: Calibri, Arial, sans-serif;">
                            ${schuljahrText}
                          </p>
                        </td>
                      </tr>
                    </table>
                  </td>
                </tr>
              </table>
            </td>
          </tr>
        </table>
        <!--[if mso]>
          </v:textbox>
        </v:rect>
        <![endif]-->
      </td>
